comments.body:
> [1987fb2](https://github.com/bitcoin/bitcoin/pull/29256/changes/1987fb2fb069197edded87e4de0ea4ddd63b4b55) _log test: verify log argument evaluation semantics_:

Nit: no biggie, but it might be simpler and more conceptually symmetric to untangle this from the previous ones by resetting the counter before the run and asserting `0` here.

```C++
BOOST_FIXTURE_TEST_CASE(logging_arg_evaluation, LogSetup)
{
    int counter{0};
    auto side_effect = [&counter] { return ++counter; };

    for (bool enable_logger : {true, false}) {
        LogInstance().DisconnectTestLogger();
        if (enable_logger) {
            BOOST_REQUIRE(LogInstance().StartLogging());
        } else {
            LogInstance().DisableLogging();
        }
        BOOST_REQUIRE_EQUAL(enable_logger, LogInstance().Enabled());

        // Info or higher should always evaluate the arguments.
        counter = 0;
        LogError("error (%s)", side_effect());
        LogWarning("warning (%s)", side_effect());
        LogInfo("info (%s)", side_effect());
        BOOST_CHECK_EQUAL(counter, 3);

        // Debug/Trace should skip argument evaluation when category is disabled.
        counter = 0;
        LogDebug(BCLog::NET, "debug (%s)", side_effect());
        LogTrace(BCLog::NET, "trace (%s)", side_effect());
        BOOST_CHECK_EQUAL(counter, 0);
    }
}
```
